/**
 * @summary OAuth callback handler
 */
export const getOauthCallbackUrl = (
  platform: string,
  params?: OauthCallbackParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/connections/oauth/${platform}/callback?${stringifiedParams}`
    : `/api/connections/oauth/${platform}/callback`;
};

export const oauthCallback = async (
  platform: string,
  params?: OauthCallbackParams,
  options?: RequestInit,
): Promise<unknown> => {
  return customFetch<unknown>(getOauthCallbackUrl(platform, params), {
    ...options,
    method: "GET",
  });
};

export const getOauthCallbackQueryKey = (
  platform: string,
  params?: OauthCallbackParams,
) => {
  return [
    `/api/connections/oauth/${platform}/callback`,
    ...(params ? [params] : []),
  ] as const;
};

export const getOauthCallbackQueryOptions = <
  TData = Awaited<ReturnType<typeof oauthCallback>>,
  TError = ErrorType<void>,
>(
  platform: string,
  params?: OauthCallbackParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof oauthCallback>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getOauthCallbackQueryKey(platform, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof oauthCallback>>> = ({
    signal,
  }) => oauthCallback(platform, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!platform,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof oauthCallback>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type OauthCallbackQueryResult = NonNullable<
  Awaited<ReturnType<typeof oauthCallback>>
>;
export type OauthCallbackQueryError = ErrorType<void>;

